<div class="card"><div class="page-title"><h1><?php echo app_lang('gd_finance_receipt'); ?> — <?php echo esc($payment->payment_number); ?></h1></div><div class="card-body"><p><strong><?php echo app_lang('gd_finance_payment_date'); ?>:</strong> <?php echo format_to_date($payment->payment_date,false); ?></p><p><strong><?php echo app_lang('gd_finance_amount'); ?>:</strong> R$ <?php echo esc($payment->amount); ?></p><p><strong><?php echo app_lang('gd_finance_method'); ?>:</strong> <?php echo app_lang('gd_finance_method_'.$payment->payment_method); ?></p><table class="table"><tr><th><?php echo app_lang('gd_finance_number'); ?></th><th><?php echo app_lang('gd_finance_description'); ?></th><th><?php echo app_lang('gd_finance_amount'); ?></th></tr><?php foreach($payment->allocations as $a): ?><tr><td><?php echo esc($a->receivable_number); ?></td><td><?php echo esc($a->description); ?></td><td><?php echo esc($a->allocated_amount); ?></td></tr><?php endforeach; ?></table><button class="btn btn-default" onclick="window.print()"><?php echo app_lang('print'); ?></button></div></div>
